            bool HasNUW = Sub->hasNoUnsignedWrap();
            bool IsNegPow2 = Mask->isNegatedPowerOf2();
            if (HasNUW || IsNegPow2) {
              APInt Common = *Mask & *C2;
              if (!Common.isZero()) {
                APInt CommonMinus1 = Common - 1;
                if ((*C2 - CommonMinus1).isPowerOf2() &&
                    ((*Mask + *C2) & CommonMinus1) == CommonMinus1) {
                  // Special case: result is just X & NewMask
                  APInt NotMask = ~(*Mask);
                  if (NotMask.isMask() && (*C2 & NotMask) == NotMask &&
                      *C2 - *C1 == NotMask) {
                    unsigned BitWidth = I.getType()->getScalarSizeInBits();
                    APInt NewMask = *Mask & APInt::getLowBitsSet(
                                               BitWidth, C2->getActiveBits());
                    return BinaryOperator::CreateAnd(
                        X, ConstantInt::get(I.getType(), NewMask));
                  }
                  // General case: (X & Mask) + (C1 - Common)
                  Value *AndInst = Builder.CreateAnd(X, MaskC);
                  APInt AddC = *C1 - Common;
                  return BinaryOperator::CreateAdd(
                      AndInst, ConstantInt::get(I.getType(), AddC));
                }
